args.query:
[
  {
    "$match": {
      "attributes": { "$ne": null },
      "description": { "$ne": null }
    }
  },
  {
    "$project": {
      "business_id": 1,
      "description": 1,
      "attributes": 1,
      "state": {
        "$regexFind": {
          "input": "$description",
          "regex": "Located at .+? in (.+?),\\s*([A-Z]{2})"
        }
      }
    }
  },
  {
    "$match": {
      "state": { "$ne": null }
    }
  },
  {
    "$project": {
      "business_id": 1,
      "description": 1,
      "attributes": 1,
      "state": { "$arrayElemAt": ["$state.captures.content", 1] },
      "has_wifi": {
        "$cond": [
          { "$regexMatch": { "input": "$attributes", "regex": "'WiFi':\\s*'(free|paid)'" } },
          true,
          false
        ]
      }
    }
  },
  {
    "$match": {
      "has_wifi": true
    }
  },
  {
    "$group": {
      "_id": "$state",
      "count": { "$sum": 1 },
      "business_ids": { "$push": "$business_id" }
    }
  },
  {
    "$sort": { "count": -1 }
  }
]

